prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?mid ?oid ?type ?messageFlowCount WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:normalizedId ?mid . }
  OPTIONAL { ?model tai:originalId ?oid . }
  OPTIONAL { ?model a ?type . }

  FILTER(
    (BOUND(?mid) && STR(?mid) = "6c9090aeef814120944b4885c7343b63") ||
    (BOUND(?oid) && STR(?oid) = "6c9090aeef814120944b4885c7343b63")
  )

  {
    SELECT (COUNT(DISTINCT ?mf) AS ?messageFlowCount) WHERE {
      ?definitions tai:belongsTo ?model .
      ?choreo tai:belongsTo ?definitions .
      ?mf a bboExt:MessageFlow ; tai:belongsTo ?choreo .
    }
  }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT
  ?messageRef
  ?messageName
  ?choreo
  ?modelName
WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId "6c9090aeef814120944b4885c7343b63" .
  OPTIONAL { ?model bbo:name ?modelName . }

  ?definitions tai:belongsTo ?model .
  ?choreo tai:belongsTo ?definitions .

  ?mf a bboExt:MessageFlow ;
      tai:belongsTo ?choreo ;
      bboExt:messageRef ?messageRef .

  OPTIONAL {
    ?msg a bboExt:Message ;
         tai:belongsTo ?choreo ;
         bbo:name ?messageName .
    FILTER(STRENDS(STR(?msg), STR(?messageRef)))
  }
}
ORDER BY ?messageName ?messageRef
LIMIT 25
